import{_ as t,W as e,X as a,Y as d}from"./framework-b9c734bc.js";const r={},i=d('<p><a href="#JSP%E5%85%A5%E9%97%A8">JSP入门</a>学习可在之前文章回顾。</p><h2 id="_1-jsp的指令" tabindex="-1"><a class="header-anchor" href="#_1-jsp的指令" aria-hidden="true">#</a> 1. JSP的指令</h2><h3 id="_1-1-作用" tabindex="-1"><a class="header-anchor" href="#_1-1-作用" aria-hidden="true">#</a> 1.1. 作用</h3><p>用于配置JSP页面，导入资源文件。</p><h3 id="_1-2-格式" tabindex="-1"><a class="header-anchor" href="#_1-2-格式" aria-hidden="true">#</a> 1.2. 格式</h3><p><code>&lt;%@ 指令名称 属性名1=属性值1 属性名2=属性值2 ... %&gt;</code>，</p><p>实例：</p><p><code>&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;</code>。</p><h3 id="_1-3-指令名称分类" tabindex="-1"><a class="header-anchor" href="#_1-3-指令名称分类" aria-hidden="true">#</a> 1.3. 指令名称分类</h3><p>共三类，包括page、include和taglib。</p><h4 id="_1-3-1-page" tabindex="-1"><a class="header-anchor" href="#_1-3-1-page" aria-hidden="true">#</a> 1.3.1. page</h4><p>配置JSP页面的，以下为page指令常用的属性名：</p><ol><li><p>contentType：等同于<code>response.setContentType()</code></p><ul><li>设置响应体的mime类型以及字符集；</li><li>设置当前jsp页面的编码（只能是高级的IDE才能生效，如果使用低级工具，则需要设置pageEncoding属性设置当前页面的字符集）；</li><li>例子：<code>&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;</code>。</li></ul></li><li><p>import：导入java代码需使用的包</p><ul><li>例子：<code>&lt;%@ page import=&quot;java.util.List&quot; %&gt;</code>。</li></ul></li><li><p>errorPage：当前页面发生异常后，会自动跳转到指定的错误页面。</p></li><li><p>isErrorPage：标识当前页面是否是错误页面。</p><ul><li>true：是，可以使用内置对象exception；</li><li>false：否。默认值。不可以使用内置对象exception。</li></ul></li></ol><h4 id="_1-3-2-include" tabindex="-1"><a class="header-anchor" href="#_1-3-2-include" aria-hidden="true">#</a> 1.3.2. include</h4><p>导入页面的资源文件，例子：<code>&lt;%@include file=&quot;top.jsp&quot;%&gt;</code>。</p><h4 id="_1-3-3-taglib" tabindex="-1"><a class="header-anchor" href="#_1-3-3-taglib" aria-hidden="true">#</a> 1.3.3. taglib</h4><p>导入资源（标签库），例子：<code>&lt;%@ taglib prefix=&quot;c&quot; uri=&quot;http://java.sun.com/jsp/jstl/core&quot; %&gt;</code>。</p><blockquote><p>这里的prefix表示之后使用该标签库的前缀，是自定义的。</p></blockquote><h2 id="_2-jsp的注释" tabindex="-1"><a class="header-anchor" href="#_2-jsp的注释" aria-hidden="true">#</a> 2. JSP的注释</h2><ol><li>html注释：</li></ol><p><code>&lt;!-- --&gt;</code>：只能注释html代码片段。</p><ol start="2"><li>jsp注释：</li></ol><p><code>&lt;%-- --%&gt;</code>：可以注释所有，包括java和html等，一般推荐使用这种方式。</p><h2 id="_3-jsp的内置对象" tabindex="-1"><a class="header-anchor" href="#_3-jsp的内置对象" aria-hidden="true">#</a> 3. JSP的内置对象</h2><p>在jsp页面中不需要创建，直接使用的对象。</p><h3 id="_3-1-9个内置对象" tabindex="-1"><a class="header-anchor" href="#_3-1-9个内置对象" aria-hidden="true">#</a> 3.1. 9个内置对象</h3><p>JSP的内置对象共9个，如下表：</p><table><thead><tr><th>变量名</th><th>真实类型</th><th>作用</th></tr></thead><tbody><tr><td>pageContext</td><td>PageContext</td><td>当前页面共享数据，还可以获取其他八个内置对象</td></tr><tr><td>request</td><td>HttpServletRequest</td><td>一次请求访问的多个资源(转发)</td></tr><tr><td>session</td><td>HttpSession</td><td>一次会话的多个请求间</td></tr><tr><td>application</td><td>ServletContext</td><td>所有用户间共享数据</td></tr><tr><td>response</td><td>HttpServletResponse</td><td>响应对象</td></tr><tr><td>page</td><td>Object</td><td>当前页面(Servlet)的对象  this</td></tr><tr><td>out</td><td>JspWriter</td><td>输出对象，数据输出到页面上</td></tr><tr><td>config</td><td>ServletConfig</td><td>Servlet的配置对象</td></tr><tr><td>exception</td><td>Throwable</td><td>异常对象，isErrorPage为true时，可以使用内置对象exception</td></tr></tbody></table>',28),o=[i];function l(p,h){return e(),a("div",null,o)}const n=t(r,[["render",l],["__file","15.JSP-more.html.vue"]]);export{n as default};
